import base64
import uuid

from app.services.carrier_client import LabelResult


class AggregatorProvider:
    def create_label(self, shipment) -> LabelResult:
        fake_pdf = base64.b64decode(
            ""
        )
        tracking_no = f"TRK{uuid.uuid4().hex[:10].upper()}"
        return LabelResult(label_bytes=fake_pdf, tracking_number=tracking_no)
